 748→      }>,
 749→    ]>(
 750→      [
 751→        "SELECT id, orchestrator_status, task_id, error_message, started_at",
 752→        "FROM agent_session",
 753→        "WHERE orchestrator_status IN ['idle', 'error']",
 754→        "AND workspace = $workspace",
 755→        "ORDER BY started_at DESC",
 756→        "LIMIT $limit;",
 757→      ].join(" "),
 758→      { workspace: input.workspaceRecord, limit: input.limit },
 759→    )
 760→    .collect<[
 761→      Array<{
 762→        id: RecordId<"agent_session", string>;
 763→        orchestrator_status: string;
 764→        task_id?: RecordId<"task", string>;
 765→        error_message?: string;
 766→        started_at: string | Date;
 767→      }>,
 768→    ]>();
 769→
 770→  const results: AgentAttentionSessionRow[] = [];
 771→
 772→  for (const row of rows) {
 773→    let taskTitle: string | undefined;
 774→    if (row.task_id) {
 775→      const taskRow = await input.surreal.select<{ title: string }>(row.task_id);
 776→      taskTitle = taskRow?.title;
 777→    }
 778→
 779→    results.push({
 780→      id: row.id,
 781→      orchestrator_status: row.orchestrator_status as "idle" | "error",
 782→      ...(row.task_id ? { task_id: row.task_id } : {}),
 783→      ...(taskTitle ? { task_title: taskTitle } : {}),
 784→      ...(row.error_message ? { error_message: row.error_message } : {}),
 785→      started_at: row.started_at,
 786→    });
 787→  }
 788→
 789→  return results;
 790→}
