454→function extractDecisionRecords(evidenceRefs?: string[]): ObserveTargetRecord[] {
455→  if (!evidenceRefs) return [];
456→  const records: ObserveTargetRecord[] = [];
457→  for (const ref of evidenceRefs) {
458→    const parsed = parseEntityRef(ref);
459→    if (parsed && parsed.table === "decision") {
460→      records.push(new RecordId("decision", parsed.id) as ObserveTargetRecord);
461→    }
462→  }
463→  return records;
464→}
