 34→
 35→const LOW_CONFIDENCE_THRESHOLD = 0.7;
 36→const STALE_DAYS = 7;
 37→const RECENT_COMPLETED_DAYS = 3;
 38→const AWARENESS_RECENCY_DAYS = 3;
 39→const FEED_ITEM_LIMIT = 20;
 40→
 41→export function createFeedRouteHandler(
 42→  deps: ServerDependencies,
 43→): (workspaceId: string) => Promise<Response> {
 44→  return (workspaceId: string) => handleFeed(deps, workspaceId);
 45→}
 46→
 47→async function handleFeed(deps: ServerDependencies, workspaceId: string): Promise<Response> {
 48→  const startedAt = performance.now();
 49→  logInfo("feed.started", "Governance feed request started", { workspaceId });
 50→
 51→  let workspaceRecord: RecordId<"workspace", string>;
 52→  try {
 53→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 54→  } catch (error) {
 55→    if (error instanceof HttpError) {
 56→      logWarn("feed.workspace_resolve.http_error", "Feed workspace resolve failed", {
 57→        workspaceId,
 58→        statusCode: error.status,
 59→      });
 60→      return jsonError(error.message, error.status);
 61→    }
 62→    logError("feed.workspace_resolve.failed", "Feed workspace resolve failed", error, { workspaceId });
 63→    return jsonError("failed to resolve workspace", 500);
 64→  }
 65→
 66→  try {
 67→    const queryInput = { surreal: deps.surreal, workspaceRecord, limit: FEED_ITEM_LIMIT };
 68→
 69→    const [
 70→      provisionalDecisions,
 71→      conflicts,
 72→      blockingQuestions,
 73→      lowConfidenceDecisions,
 74→      blockedTasks,
 75→      observations,
 76→      suggestions,
 77→      staleTasks,
 78→      recentlyCompleted,
 79→      recentExtractions,
 80→      agentAttentionSessions,
 81→      pendingVetoIntents,
 82→      recentlyVetoedIntents,
 83→    ] = await Promise.all([
 84→      listProvisionalDecisions(queryInput),
 85→      listWorkspaceConflicts(queryInput),
 86→      listBlockingQuestions(queryInput),
 87→      listLowConfidenceDecisions({ ...queryInput, confidenceThreshold: LOW_CONFIDENCE_THRESHOLD }),
 88→      listBlockedTasks(queryInput),
 89→      listWorkspaceOpenObservations({ surreal: deps.surreal, workspaceRecord, limit: FEED_ITEM_LIMIT }),
 90→      listWorkspacePendingSuggestions({ surreal: deps.surreal, workspaceRecord, limit: FEED_ITEM_LIMIT }),
 91→      listStaleTasks({ ...queryInput, staleDays: STALE_DAYS }),
 92→      listRecentlyCompletedItems({ ...queryInput, recentDays: RECENT_COMPLETED_DAYS }),
 93→      listRecentExtractions({ ...queryInput, cutoff: new Date(Date.now() - AWARENESS_RECENCY_DAYS * 24 * 60 * 60 * 1000) }),
 94→      listAgentAttentionSessions(queryInput),
 95→      listPendingVetoIntents(queryInput),
 96→      listRecentlyVetoedIntents(queryInput),
 97→    ]);
 98→
 99→    const blocking: GovernanceFeedItem[] = [];
100→    const review: GovernanceFeedItem[] = [];
101→    const awareness: GovernanceFeedItem[] = [];
102→
103→    // Blocking: provisional decisions
104→    for (const row of provisionalDecisions) {
105→      const rawId = row.id.id as string;
106→      blocking.push({
107→        id: `decision:${rawId}:${row.status}`,
108→        tier: "blocking",
109→        entityId: `decision:${rawId}`,
110→        entityKind: "decision",
111→        entityName: row.summary,
112→        reason: `${capitalize(row.status)} decision awaiting confirmation`,
113→        status: row.status,
114→        ...(row.project ? { project: row.project } : {}),
115→        ...(row.category ? { category: row.category as EntityCategory } : {}),
116→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
117→        createdAt: toIsoString(row.created_at),
118→        actions: decisionActions(),
119→      });
120→    }
121→
122→    // Blocking: conflicts
123→    for (const row of conflicts) {
124→      blocking.push({
125→        id: `conflict:${row.edgeId}`,
126→        tier: "blocking",
127→        entityId: `${row.fromKind}:${row.fromRecord.id as string}`,
128→        entityKind: row.fromKind as EntityKind,
129→        entityName: row.fromName,
130→        reason: row.description ?? `Conflicts with ${row.toName}`,
131→        status: "conflict",
132→        ...(row.severity ? { severity: row.severity as ObservationSeverity } : {}),
133→        createdAt: row.detectedAt,
134→        actions: conflictActions(),
135→        conflictTarget: {
136→          entityId: `${row.toKind}:${row.toRecord.id as string}`,
137→          entityKind: row.toKind as EntityKind,
138→          entityName: row.toName,
139→        },
140→      });
141→    }
142→
143→    // Blocking: high/critical questions
144→    for (const row of blockingQuestions) {
145→      const rawId = row.id.id as string;
146→      blocking.push({
147→        id: `question:${rawId}:blocking`,
148→        tier: "blocking",
149→        entityId: `question:${rawId}`,
150→        entityKind: "question",
151→        entityName: row.text,
152→        reason: `${capitalize(row.priority)} priority open question`,
153→        status: row.status,
154→        ...(row.project ? { project: row.project } : {}),
155→        ...(row.category ? { category: row.category as EntityCategory } : {}),
156→        priority: row.priority as EntityPriority,
157→        createdAt: toIsoString(row.created_at),
158→        actions: questionActions(),
159→      });
160→    }
161→
162→    // Blocking + Review: agent attention sessions (error -> blocking, idle -> review)
163→    for (const session of agentAttentionSessions) {
164→      const item = mapAgentSessionToFeedItem(session);
165→      if (item.tier === "blocking") {
166→        blocking.push(item);
167→      } else {
168→        review.push(item);
169→      }
170→    }
171→
172→    // Blocking: pending veto intents (agent actions awaiting human review)
173→    for (const intent of pendingVetoIntents) {
174→      blocking.push(mapPendingIntentToFeedItem(intent));
175→    }
176→
177→    // Review: low confidence decisions
178→    for (const row of lowConfidenceDecisions) {
179→      const rawId = row.id.id as string;
180→      review.push({
181→        id: `decision:${rawId}:low_confidence`,
182→        tier: "review",
183→        entityId: `decision:${rawId}`,
184→        entityKind: "decision",
185→        entityName: row.summary,
186→        reason: `Low confidence inferred decision (${Math.round(row.extraction_confidence * 100)}%)`,
187→        status: row.status,
188→        ...(row.project ? { project: row.project } : {}),
189→        ...(row.category ? { category: row.category as EntityCategory } : {}),
190→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
191→        createdAt: toIsoString(row.created_at),
192→        actions: decisionActions(),
193→      });
194→    }
195→
196→    // Review: blocked tasks
197→    for (const row of blockedTasks) {
198→      const rawId = row.id.id as string;
199→      review.push({
200→        id: `task:${rawId}:blocked`,
201→        tier: "review",
202→        entityId: `task:${rawId}`,
203→        entityKind: "task",
204→        entityName: row.title,
205→        reason: "Task is blocked",
206→        status: row.status,
207→        ...(row.project ? { project: row.project } : {}),
208→        ...(row.category ? { category: row.category as EntityCategory } : {}),
209→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
210→        createdAt: toIsoString(row.created_at),
211→        actions: blockedTaskActions(),
212→      });
213→    }
214→
215→    // Review: all open/acknowledged observations need human action
216→    for (const obs of observations) {
217→      review.push({
218→        id: `observation:${obs.id}:${obs.severity}`,
219→        tier: "review",
220→        entityId: `observation:${obs.id}`,
221→        entityKind: "observation",
222→        entityName: obs.text,
223→        reason: `${capitalize(obs.severity)} observation from ${obs.sourceAgent}`,
224→        status: obs.status,
225→        ...(obs.category ? { category: obs.category } : {}),
226→        severity: obs.severity,
227→        createdAt: obs.createdAt,
228→        actions: observationActions(obs.status),
229→      });
230→    }
231→
232→    // Review: pending suggestions from agents
233→    for (const sug of suggestions) {
234→      review.push({
235→        id: `suggestion:${sug.id}:${sug.category}`,
236→        tier: "review",
237→        entityId: `suggestion:${sug.id}`,
238→        entityKind: "suggestion",
239→        entityName: sug.text,
240→        reason: `${capitalize(sug.category)} suggestion from ${sug.suggestedBy} (confidence ${Math.round(sug.confidence * 100)}%)`,
241→        status: sug.status,
242→        createdAt: sug.createdAt,
243→        actions: suggestionActions(),
244→      });
245→    }
246→
247→    // Awareness items are filtered to the last AWARENESS_RECENCY_DAYS
248→    const awarenessCutoff = new Date(Date.now() - AWARENESS_RECENCY_DAYS * 24 * 60 * 60 * 1000);
249→
250→    // Awareness: stale tasks (only if they crossed the stale threshold recently)
251→    for (const row of staleTasks) {
252→      const ts = row.updated_at ? new Date(row.updated_at) : new Date(row.created_at);
253→      if (ts < awarenessCutoff) continue;
254→      const rawId = row.id.id as string;
255→      awareness.push({
256→        id: `task:${rawId}:stale`,
257→        tier: "awareness",
258→        entityId: `task:${rawId}`,
259→        entityKind: "task",
260→        entityName: row.title,
261→        reason: `Task open for over ${STALE_DAYS} days`,
262→        status: row.status,
263→        ...(row.project ? { project: row.project } : {}),
264→        ...(row.category ? { category: row.category as EntityCategory } : {}),
265→        ...(row.priority ? { priority: row.priority as EntityPriority } : {}),
266→        createdAt: toIsoString(row.created_at),
267→        actions: staleTaskActions(),
268→      });
269→    }
270→
271→    // Awareness: recently completed (already filtered by RECENT_COMPLETED_DAYS query)
272→    for (const row of recentlyCompleted) {
273→      const rawId = row.id.id as string;
274→      awareness.push({
275→        id: `${row.kind}:${rawId}:completed`,
276→        tier: "awareness",
277→        entityId: `${row.kind}:${rawId}`,
278→        entityKind: row.kind as EntityKind,
279→        entityName: row.name,
280→        reason: `Recently completed ${row.kind}`,
281→        status: row.status,
282→        ...(row.project ? { project: row.project } : {}),
283→        ...(row.category ? { category: row.category as EntityCategory } : {}),
284→        createdAt: toIsoString(row.updated_at),
285→        actions: [],
286→      });
287→    }
288→
289→    // Awareness: recently vetoed intents (dedup against blocking tier pending_veto intents)
290→    const blockingEntityIds = new Set<string>(blocking.map((item) => item.entityId));
291→    for (const row of recentlyVetoedIntents) {
292→      const entityId = `intent:${row.id.id as string}`;
293→      if (blockingEntityIds.has(entityId)) continue;
294→      awareness.push(mapVetoedIntentToFeedItem(row));
295→    }
296→
297→    // Awareness: recent extractions (skip entities already in higher tiers)
298→    const seenEntityIds = new Set<string>();
299→    for (const item of [...blocking, ...review, ...awareness]) {
300→      seenEntityIds.add(item.entityId);
301→    }
302→    for (const row of recentExtractions) {
303→      const entityId = `${row.entityKind}:${row.entityId}`;
304→      if (seenEntityIds.has(entityId)) continue;
305→      awareness.push({
306→        id: `extraction:${row.edgeId}`,
307→        tier: "awareness",
308→        entityId,
309→        entityKind: row.entityKind as EntityKind,
310→        entityName: row.entityName,
311→        reason: `Extracted from ${row.sourceKind.replace("_", " ")}`,
312→        status: "extracted",
313→        createdAt: row.extractedAt,
314→        actions: row.entityKind === "question" ? questionActions() : [],
315→      });
316→    }
317→
318→    const payload: GovernanceFeedResponse = {
319→      blocking,
320→      review,
321→      awareness,
322→      updatedAt: new Date().toISOString(),
323→    };
324→
325→    logInfo("feed.completed", "Governance feed request completed", {
326→      workspaceId,
327→      blockingCount: blocking.length,
328→      reviewCount: review.length,
329→      awarenessCount: awareness.length,
330→      durationMs: elapsedMs(startedAt),
331→    });
332→
333→    return jsonResponse(payload, 200);
334→  } catch (error) {
335→    logError("feed.failed", "Governance feed request failed", error, { workspaceId });
336→    const message = error instanceof Error ? error.message : "feed request failed";
337→    return jsonError(message, 500);
338→  }
339→}
