135→export async function listWorkspacePendingSuggestions(input: {
136→  surreal: Surreal;
137→  workspaceRecord: RecordId<"workspace", string>;
138→  limit: number;
139→}): Promise<SuggestionSummary[]> {
140→  const [rows] = await input.surreal
141→    .query<[
142→      Array<{
143→        id: SuggestionRecord;
144→        text: string;
145→        category: SuggestionCategory;
146→        rationale: string;
147→        suggested_by: string;
148→        confidence: number;
149→        status: SuggestionStatus;
150→        created_at: string | Date;
151→      }>,
152→    ]>(
153→      [
154→        "SELECT id, text, category, rationale, suggested_by, confidence, status, created_at",
155→        "FROM suggestion",
156→        "WHERE workspace = $workspace",
157→        "AND status IN ['pending', 'deferred']",
158→        "ORDER BY confidence DESC, created_at DESC",
159→        "LIMIT $limit;",
160→      ].join(" "),
161→      {
162→        workspace: input.workspaceRecord,
163→        limit: input.limit,
164→      },
165→    )
166→    .collect<[
167→      Array<{
168→        id: SuggestionRecord;
169→        text: string;
170→        category: SuggestionCategory;
171→        rationale: string;
172→        suggested_by: string;
173→        confidence: number;
174→        status: SuggestionStatus;
175→        created_at: string | Date;
176→      }>,
177→    ]>();
178→
179→  return rows.map((row) => ({
180→    id: row.id.id as string,
181→    text: row.text,
182→    category: row.category,
183→    rationale: row.rationale,
184→    suggestedBy: row.suggested_by,
185→    confidence: row.confidence,
186→    status: row.status,
187→    createdAt: row.created_at instanceof Date ? row.created_at.toISOString() : new Date(row.created_at).toISOString(),
188→  }));
189→}
